import { NextResponse } from 'next/server';
import { analyzeSchema } from '@/lib/validators';
import { scrapeWebsite } from '@/services/scraper';
import { extractDesignTokens } from '@/services/tokenExtractor';
import { prisma } from '@/lib/prisma';

export async function POST(req: Request) {
  try {
    const body = await req.json();

    // Validate request body
    const result = analyzeSchema.safeParse(body);
    if (!result.success) {
      return NextResponse.json(
        { success: false, error: result.error.issues[0].message },
        { status: 400 }
      );
    }

    const { url } = result.data;

    // Run scraper
    const analysis = await scrapeWebsite(url);

    if (!analysis.success || !('site' in analysis)) {
      return NextResponse.json(
        { success: false, error: (analysis as any).error || 'Failed to analyze website' },
        { status: 500 }
      );
    }

    // Extract structured design tokens
    const tokens = extractDesignTokens(analysis);

    // Save to database
    try {
      await prisma.designToken.create({
        data: {
          siteUrl: url,
          tokens: tokens as any,
        }
      });
    } catch (dbError) {
      console.error('Database Save Error:', dbError);
      // Continue even if DB fails, core feature is analysis
    }

    return NextResponse.json({
      success: true,
      site: analysis.site,
      styles: analysis.styles,
      tokens
    });
  } catch (error: any) {
    console.error('API Error:', error);
    return NextResponse.json(
      { success: false, error: 'An unexpected error occurred' },
      { status: 500 }
    );
  }
}

import { NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';

export async function POST(req: Request) {
  try {
    const { url, tokens, changes } = await req.json();

    if (!url || !tokens) {
      return NextResponse.json({ error: 'URL and tokens are required' }, { status: 400 });
    }

    // Get current version count for this site
    const count = await prisma.versionHistory.count({
      where: { siteUrl: url },
    });

    const version = await prisma.versionHistory.create({
      data: {
        siteUrl: url,
        version: count + 1,
        tokens: tokens,
        changes: changes || {},
      },
    });

    return NextResponse.json({ success: true, version });
  } catch (error: any) {
    console.error('History Save Error:', error);
    return NextResponse.json({ error: 'Failed to save version' }, { status: 500 });
  }
}

export async function GET(req: Request) {
  const { searchParams } = new URL(req.url);
  const url = searchParams.get('url');

  if (!url) {
    return NextResponse.json({ error: 'URL is required' }, { status: 400 });
  }

  try {
    const history = await prisma.versionHistory.findMany({
      where: { siteUrl: url },
      orderBy: { version: 'desc' },
      take: 10,
    });

    return NextResponse.json({ success: true, history });
  } catch (error: any) {
    console.error('History Fetch Error:', error);
    return NextResponse.json({ error: 'Failed to fetch history' }, { status: 500 });
  }
}

'use client';

import { DashboardShell } from '@/components/dashboard/DashboardShell';
