import puppeteer from 'puppeteer';

export async function scrapeWebsite(url: string) {
  let browser;
  try {
    browser = await puppeteer.launch({
      headless: true,
      args: ['--no-sandbox', '--disable-setuid-sandbox'],
    });

    const page = await browser.newPage();

    // Set a realistic viewport
    await page.setViewport({ width: 1280, height: 800 });

    // Navigate with timeout
    await page.goto(url, { waitUntil: 'networkidle2', timeout: 30000 });

    const data = await page.evaluate(() => {
      // Helper to get computed styles
      const getStyle = (el: Element | null, prop: string) => {
        if (!el) return '';
        return window.getComputedStyle(el).getPropertyValue(prop);
      };

      // Extract basic info
      const title = document.title || '';
      const description = document.querySelector('meta[name="description"]')?.getAttribute('content') || '';

      // Style extraction
      const backgroundColor = getStyle(document.body, 'background-color');
      const fontFamily = getStyle(document.body, 'font-family').split(',')[0].replace(/['"]/g, '');

      // Heuristic for primary button color
      const buttons = Array.from(document.querySelectorAll('button, a[role="button"], .btn, .button'));
      let primaryButtonColor = '#6C3EF4'; // Default fallback

      if (buttons.length > 0) {
        // Try to find the first button that isn't transparent
        for (const btn of buttons) {
          const bg = window.getComputedStyle(btn).backgroundColor;
          if (bg && bg !== 'rgba(0, 0, 0, 0)' && bg !== 'transparent' && bg !== 'rgb(255, 255, 255)') {
            primaryButtonColor = bg;
            break;
          }
        }
      }

      // Heading font size (primary H1)
      const h1 = document.querySelector('h1');
      const headingFontSize = h1 ? getStyle(h1, 'font-size') : getStyle(document.body, 'font-size');

      // Stylesheets count
      const stylesheets = document.querySelectorAll('link[rel="stylesheet"]').length;

      return {
        site: {
          title,
          description,
        },
        styles: {
          backgroundColor,
          fontFamily,
          primaryButtonColor,
          headingFontSize,
          stylesheetsCount: stylesheets
        }
      };
    });

    return { success: true, ...data };
  } catch (error: any) {
    console.error('Scraping error:', error);
    return { 
      success: false, 
      error: error.message || 'Failed to analyze website' 
    };
  } finally {
    if (browser) {
      await browser.close();
    }
  }
}

import { DesignTokens } from "@/types/designTokens";
import { normalizeFontSize, normalizeFontWeight, normalizeLineHeight } from "@/utils/typographyUtils";
import { generateSpacingScale } from "@/utils/spacingUtils";
import { classifyColors } from "./colorAnalyzer";

export const extractDesignTokens = (scrapedData: any): DesignTokens => {
  const { styles, site } = scrapedData;

  // 1. Colors
  const rawColors = [
    styles.backgroundColor,
    styles.primaryButtonColor,
    // Add more if scraper gets them
  ];
  const colors = classifyColors(rawColors);

  // 2. Typography
  const typography = {
    fontFamily: styles.fontFamily || 'Inter',
    h1: normalizeFontSize(styles.headingFontSize || '32px'),
    h2: normalizeFontSize('24px'),
    h3: normalizeFontSize('20px'),
    body: normalizeFontSize('16px'),
    caption: normalizeFontSize('12px'),
    lineHeight: '1.5',
    fontWeight: {
      regular: 400,
      medium: 500,
      bold: 700,
    }
  };

  // 3. Spacing
  const spacing = generateSpacingScale(['4px', '8px', '16px', '24px', '32px']);

  // 4. Radius
  const radius = {
    sm: '4px',
    md: '8px',
    lg: '16px',
  };

  // 5. Shadows
  const shadows = {
    card: '0 4px 6px rgba(0,0,0,0.1)',
    button: '0 2px 4px rgba(0,0,0,0.08)',
  };

  return {
    colors,
    typography,
    spacing,
    radius,
    shadows,
  };
};

import { create } from 'zustand';
import { AnalysisState, AnalysisResponse } from '@/types';
import { DesignTokens } from '@/types/designTokens';

interface TokenStore extends AnalysisState {
  tokens: DesignTokens | null;
  lockedTokens: Record<string, boolean>;
  versionHistory: any[];
  setLoading: (isLoading: boolean) => void;
  setResult: (result: AnalysisResponse | null) => void;
  setTokens: (tokens: DesignTokens | null) => void;
  setVersionHistory: (history: any[]) => void;
  setError: (error: string | null) => void;
  setUrl: (url: string) => void;
  lockToken: (path: string) => void;
  unlockToken: (path: string) => void;
  updateColor: (key: keyof DesignTokens['colors'], value: string) => void;
  updateTypography: (key: keyof DesignTokens['typography'], value: any) => void;
  updateSpacing: (key: string, value: string) => void;
  updateRadius: (key: keyof DesignTokens['radius'], value: string) => void;
  restoreVersion: (tokens: DesignTokens) => void;
  reset: () => void;
}

export const useTokenStore = create<TokenStore>((set) => ({
  url: '',
  isLoading: false,
  result: null,
  tokens: null,
  lockedTokens: {},
  versionHistory: [],
  error: null,
  setLoading: (isLoading) => set({ isLoading }),
  setResult: (result) => set({ result, isLoading: false, error: null }),
  setTokens: (newTokens) => set((state) => {
    if (!state.tokens || !newTokens) return { tokens: newTokens };

    // Merge only if not locked
    const mergedTokens = { ...newTokens };

    // Helper to merge nested objects while respecting locks
    const mergeWithLocks = (target: any, source: any, prefix: string) => {
      Object.keys(source).forEach(key => {
        const path = `${prefix}.${key}`;
        if (state.lockedTokens[path]) {
          target[key] = (state.tokens as any)[prefix][key];
        }
      });
    };

    mergeWithLocks(mergedTokens.colors, newTokens.colors, 'colors');
    mergeWithLocks(mergedTokens.typography, newTokens.typography, 'typography');
    mergeWithLocks(mergedTokens.spacing, newTokens.spacing, 'spacing');
    mergeWithLocks(mergedTokens.radius, newTokens.radius, 'radius');

    return { tokens: mergedTokens };
  }),
  setVersionHistory: (versionHistory) => set({ versionHistory }),
  setError: (error) => set({ error, isLoading: false }),
  setUrl: (url) => set({ url }),
  lockToken: (path) => set((state) => ({
    lockedTokens: { ...state.lockedTokens, [path]: true }
  })),
  unlockToken: (path) => set((state) => ({
    lockedTokens: { ...state.lockedTokens, [path]: false }
  })),
  updateColor: (key, value) => set((state) => ({
    tokens: state.tokens ? {
      ...state.tokens,
      colors: { ...state.tokens.colors, [key]: value }
    } : null
  })),
  updateTypography: (key, value) => set((state) => ({
    tokens: state.tokens ? {
      ...state.tokens,
      typography: { ...state.tokens.typography, [key]: value }
    } : null
  })),
  updateSpacing: (key, value) => set((state) => ({
    tokens: state.tokens ? {
      ...state.tokens,
      spacing: { ...state.tokens.spacing, [key]: value }
    } : null
  })),
  updateRadius: (key, value) => set((state) => ({
    tokens: state.tokens ? {
      ...state.tokens,
      radius: { ...state.tokens.radius, [key]: value }
    } : null
  })),
  restoreVersion: (tokens) => set({ tokens }),
  reset: () => set({ url: '', isLoading: false, result: null, tokens: null, lockedTokens: {}, versionHistory: [], error: null }),
}));

export const normalizeSpacingValue = (value: string): string => {
  const num = parseFloat(value);
  if (isNaN(num)) return value;

  if (num === 0) return '0px';

  // Standard spacing scale (4px based)
  const scale = [2, 4, 8, 12, 16, 20, 24, 32, 40, 48, 64, 80, 96];
  const closest = scale.reduce((prev, curr) => 
    Math.abs(curr - num) < Math.abs(prev - num) ? curr : prev
  );

  return `${closest}px`;
};

export const generateSpacingScale = (values: string[]): Record<string, string> => {
  const nums = values.map(v => parseFloat(v)).filter(n => !isNaN(n) && n > 0);
  const unique = Array.from(new Set(nums)).sort((a, b) => a - b);

  const scale: Record<string, string> = {
    xs: normalizeSpacingValue('4px'),
    sm: normalizeSpacingValue('8px'),
    md: normalizeSpacingValue('16px'),
    lg: normalizeSpacingValue('24px'),
    xl: normalizeSpacingValue('32px'),
  };

  // If we found specific spacing values, we could try to map them to the scale
  // But for now, we'll return a normalized default scale based on the request
  return scale;
};
